using System.Text;
using static TerminalHyperspace.Importer.Parsers;

namespace TerminalHyperspace.Importer;

public class Emitter
{
    private readonly ImportContext _ctx;
    private readonly string _outDir;

    private static readonly string[] Attrs =
        { "Dexterity", "Knowledge", "Mechanical", "Perception", "Strength", "Technical", "Force" };

    private const string Header =
        "// <auto-generated/>\n" +
        "// Generated by th-import. Do not edit by hand — re-run the importer to regenerate.\n";

    public Emitter(ImportContext ctx, string outDir)
    {
        _ctx = ctx;
        _outDir = outDir;
    }

    public int EmitAll()
    {
        int total = 0;
        total += EmitItems();
        total += EmitArmorAndShields();
        total += EmitVehicles();
        total += EmitNPCs();
        total += EmitSpaceEncounters();
        total += EmitSpecies();
        total += EmitRoles();
        total += EmitSkillChecks();
        total += EmitLocations();
        return total;
    }

    private void Write(string fileName, string content)
        => File.WriteAllText(Path.Combine(_outDir, fileName), content);

    // =================================================================
    // Items
    // =================================================================
    private int EmitItems()
    {
        if (_ctx.Items.Count == 0) return 0;
        var sb = new StringBuilder();
        sb.Append(Header);
        sb.AppendLine("using TerminalHyperspace.Models;");
        sb.AppendLine();
        sb.AppendLine("namespace TerminalHyperspace.Content;");
        sb.AppendLine();
        sb.AppendLine("public static partial class ItemData");
        sb.AppendLine("{");
        foreach (var r in _ctx.Items)
        {
            var id = r.Get("Id");
            var isWeapon = ParseBool(r.Get("IsWeapon"));
            var isCons = ParseBool(r.Get("IsConsumable"));
            sb.AppendLine($"    public static Item {id} => new()");
            sb.AppendLine("    {");
            sb.AppendLine($"        Name = {Quote(r.Get("Name"))},");
            if (!string.IsNullOrEmpty(r.Get("Description")))
                sb.AppendLine($"        Description = {Quote(r.Get("Description"))},");
            sb.AppendLine($"        IsWeapon = {(isWeapon ? "true" : "false")},");
            if (isWeapon)
            {
                sb.AppendLine($"        Damage = {DiceLiteral(r.Get("Damage"))},");
                if (!string.IsNullOrEmpty(r.Get("AttackSkill")))
                    sb.AppendLine($"        AttackSkill = SkillType.{r.Get("AttackSkill")},");
                sb.AppendLine($"        Range = {ParseInt(r.Get("Range"))},");
            }
            sb.AppendLine($"        Price = {ParseInt(r.Get("Price"))},");
            if (isCons) sb.AppendLine("        IsConsumable = true,");
            sb.AppendLine("    };");
            sb.AppendLine();
        }
        sb.AppendLine("}");
        Write("ItemData.Generated.cs", sb.ToString());
        return _ctx.Items.Count;
    }

    // =================================================================
    // Armor + Shields
    // =================================================================
    private int EmitArmorAndShields()
    {
        int n = 0;
        if (_ctx.Armor.Count > 0)
        {
            var sb = new StringBuilder();
            sb.Append(Header);
            sb.AppendLine("using TerminalHyperspace.Models;");
            sb.AppendLine();
            sb.AppendLine("namespace TerminalHyperspace.Content;");
            sb.AppendLine();
            sb.AppendLine("public static partial class ArmorData");
            sb.AppendLine("{");
            foreach (var r in _ctx.Armor)
            {
                var id = r.Get("Id");
                sb.AppendLine($"    public static readonly Armor {id} = new()");
                sb.AppendLine("    {");
                sb.AppendLine($"        Name = {Quote(r.Get("Name"))},");
                sb.AppendLine($"        DiceCode = {DiceLiteral(r.Get("DiceCode"))},");
                sb.AppendLine($"        Price = {ParseInt(r.Get("Price"))},");
                var clim = r.Get("Climate");
                if (!string.IsNullOrEmpty(clim) && !clim.Equals("Normal", StringComparison.OrdinalIgnoreCase))
                    sb.AppendLine($"        Climate = Climate.{clim},");
                sb.AppendLine("    };");
                sb.AppendLine();
                n++;
            }
            sb.AppendLine("}");
            Write("ArmorData.Generated.cs", sb.ToString());
        }
        if (_ctx.Shields.Count > 0)
        {
            var sb = new StringBuilder();
            sb.Append(Header);
            sb.AppendLine("using TerminalHyperspace.Models;");
            sb.AppendLine();
            sb.AppendLine("namespace TerminalHyperspace.Content;");
            sb.AppendLine();
            sb.AppendLine("public static partial class ShieldData");
            sb.AppendLine("{");
            foreach (var r in _ctx.Shields)
            {
                var id = r.Get("Id");
                sb.AppendLine($"    public static readonly VehicleShield {id} = new()");
                sb.AppendLine("    {");
                sb.AppendLine($"        Name = {Quote(r.Get("Name"))},");
                sb.AppendLine($"        DiceCode = {DiceLiteral(r.Get("DiceCode"))},");
                sb.AppendLine($"        Price = {ParseInt(r.Get("Price"))},");
                sb.AppendLine("    };");
                sb.AppendLine();
                n++;
            }
            sb.AppendLine("}");
            Write("ShieldData.Generated.cs", sb.ToString());
        }
        return n;
    }

    // =================================================================
    // Vehicles
    // =================================================================
    private int EmitVehicles()
    {
        if (_ctx.Vehicles.Count == 0) return 0;
        var sb = new StringBuilder();
        sb.Append(Header);
        sb.AppendLine("using TerminalHyperspace.Models;");
        sb.AppendLine();
        sb.AppendLine("namespace TerminalHyperspace.Content;");
        sb.AppendLine();
        sb.AppendLine("public static partial class VehicleData");
        sb.AppendLine("{");
        foreach (var r in _ctx.Vehicles)
        {
            sb.AppendLine($"    public static Vehicle {r.Get("Id")} => new()");
            sb.AppendLine("    {");
            sb.AppendLine($"        Name = {Quote(r.Get("Name"))},");
            if (!string.IsNullOrEmpty(r.Get("Description")))
                sb.AppendLine($"        Description = {Quote(r.Get("Description"))},");
            sb.AppendLine($"        IsSpace = {(ParseBool(r.Get("IsSpace")) ? "true" : "false")},");
            sb.AppendLine($"        Maneuverability = {DiceLiteral(r.Get("Maneuverability"))},");
            sb.AppendLine($"        Resolve = {ParseInt(r.Get("Resolve"))},");
            var shield = r.Get("Shield");
            if (!string.IsNullOrEmpty(shield)) sb.AppendLine($"        Shield = ShieldData.{shield},");
            EmitVehicleWeapons(sb, r.Get("Weapons"), indent: "        ");
            EmitVehicleEquipment(sb, r.Get("Equipment"), indent: "        ");
            sb.AppendLine($"        Price = {ParseInt(r.Get("Price"))},");
            sb.AppendLine("    };");
            sb.AppendLine();
        }
        sb.AppendLine("}");
        Write("VehicleData.Generated.cs", sb.ToString());
        return _ctx.Vehicles.Count;
    }

    private static void EmitVehicleWeapons(StringBuilder sb, string raw, string indent)
    {
        var tuples = SplitTuples(raw);
        if (tuples.Count == 0) return;
        sb.AppendLine($"{indent}Weapons = new()");
        sb.AppendLine($"{indent}{{");
        foreach (var t in tuples)
        {
            if (t.Length < 3) continue;
            sb.AppendLine($"{indent}    new() {{ Name = {Quote(t[0])}, Damage = {DiceLiteral(t[1])}, AttackSkill = SkillType.{t[2]} }},");
        }
        sb.AppendLine($"{indent}}},");
    }

    private static void EmitVehicleEquipment(StringBuilder sb, string raw, string indent)
    {
        var tuples = SplitTuples(raw);
        if (tuples.Count == 0) return;
        sb.AppendLine($"{indent}Equipment = new()");
        sb.AppendLine($"{indent}{{");
        foreach (var t in tuples)
        {
            if (t.Length < 3) continue;
            sb.AppendLine($"{indent}    new() {{ Name = {Quote(t[0])}, BonusSkill = SkillType.{t[1]}, Bonus = {DiceLiteral(t[2])} }},");
        }
        sb.AppendLine($"{indent}}},");
    }

    // =================================================================
    // NPCs
    // =================================================================
    private int EmitNPCs()
    {
        if (_ctx.NPCs.Count == 0) return 0;
        var sb = new StringBuilder();
        sb.Append(Header);
        sb.AppendLine("using TerminalHyperspace.Models;");
        sb.AppendLine();
        sb.AppendLine("namespace TerminalHyperspace.Content;");
        sb.AppendLine();
        sb.AppendLine("public static partial class NPCData");
        sb.AppendLine("{");
        foreach (var r in _ctx.NPCs)
        {
            EmitCharacterFactory(sb, r.Get("Id"), r, methodKind: "method");
            sb.AppendLine();
        }
        sb.AppendLine("}");
        Write("NPCData.Generated.cs", sb.ToString());
        return _ctx.NPCs.Count;
    }

    /// Emits a Character factory. methodKind: "method" → public static Character X() => new() {...};
    /// "expr" → emits as inline `new Character { ... }` (used inside SpaceEncounters).
    private static void EmitCharacterFactory(StringBuilder sb, string id, Row r, string methodKind, string indent = "    ")
    {
        var name = r.Get("DisplayName");
        if (string.IsNullOrEmpty(name)) name = r.Get("Pilot.Name");
        if (string.IsNullOrEmpty(name)) name = id;

        if (methodKind == "method")
        {
            sb.AppendLine($"{indent}public static Character {id}() => new()");
            sb.AppendLine($"{indent}{{");
        }
        else
        {
            sb.AppendLine($"{indent}new Character");
            sb.AppendLine($"{indent}{{");
        }
        var inner = indent + "    ";
        sb.AppendLine($"{inner}Name = {Quote(name)},");
        sb.AppendLine($"{inner}IsPlayer = false,");
        sb.AppendLine($"{inner}Attributes = new()");
        sb.AppendLine($"{inner}{{");
        foreach (var a in Attrs)
        {
            var dice = r.Get(a);
            if (string.IsNullOrEmpty(dice)) dice = r.Get($"Pilot.{a}");
            if (string.IsNullOrEmpty(dice)) dice = "0D";
            sb.AppendLine($"{inner}    [AttributeType.{a}] = {DiceLiteral(dice)},");
        }
        sb.AppendLine($"{inner}}},");

        var skillBonusSrc = !string.IsNullOrEmpty(r.Get("SkillBonuses")) ? r.Get("SkillBonuses") : r.Get("Pilot.SkillBonuses");
        var bonuses = SplitKeyVal(skillBonusSrc);
        if (bonuses.Count > 0)
        {
            sb.AppendLine($"{inner}SkillBonuses = new()");
            sb.AppendLine($"{inner}{{");
            foreach (var (skill, dice) in bonuses)
                sb.AppendLine($"{inner}    [SkillType.{skill}] = {DiceLiteral(dice)},");
            sb.AppendLine($"{inner}}},");
        }

        var inv = SplitSemi(r.Get("Inventory"));
        if (inv.Count > 0)
        {
            sb.AppendLine($"{inner}Inventory = new() {{ {string.Join(", ", inv.Select(i => $"ItemData.{i}"))} }},");
        }

        var weapon = r.Get("EquippedWeapon");
        if (!string.IsNullOrEmpty(weapon))
            sb.AppendLine($"{inner}EquippedWeapon = ItemData.{weapon},");

        var armor = !string.IsNullOrEmpty(r.Get("EquippedArmor")) ? r.Get("EquippedArmor") : r.Get("Pilot.EquippedArmor");
        if (!string.IsNullOrEmpty(armor))
            sb.AppendLine($"{inner}EquippedArmor = ArmorData.{armor},");

        if (methodKind == "method")
            sb.AppendLine($"{indent}}};");
        else
            sb.AppendLine($"{indent}}}");
    }

    // =================================================================
    // SpaceEncounters
    // =================================================================
    private int EmitSpaceEncounters()
    {
        if (_ctx.SpaceEncounters.Count == 0) return 0;
        var sb = new StringBuilder();
        sb.Append(Header);
        sb.AppendLine("using TerminalHyperspace.Models;");
        sb.AppendLine();
        sb.AppendLine("namespace TerminalHyperspace.Content;");
        sb.AppendLine();
        sb.AppendLine("public static partial class SpaceEncounterData");
        sb.AppendLine("{");
        foreach (var r in _ctx.SpaceEncounters)
        {
            var id = r.Get("Id");
            sb.AppendLine($"    public static SpaceEncounter {id}() => new()");
            sb.AppendLine("    {");
            sb.AppendLine("        Pilot =");
            EmitCharacterFactory(sb, id, r, methodKind: "expr", indent: "            ");
            sb.AppendLine("        ,");

            sb.AppendLine("        Ship = new Vehicle");
            sb.AppendLine("        {");
            sb.AppendLine($"            Name = {Quote(r.Get("Ship.Name"))},");
            if (!string.IsNullOrEmpty(r.Get("Ship.Description")))
                sb.AppendLine($"            Description = {Quote(r.Get("Ship.Description"))},");
            sb.AppendLine("            IsSpace = true,");
            sb.AppendLine($"            Maneuverability = {DiceLiteral(r.Get("Ship.Maneuverability"))},");
            sb.AppendLine($"            Resolve = {ParseInt(r.Get("Ship.Resolve"))},");
            var shield = r.Get("Ship.Shield");
            if (!string.IsNullOrEmpty(shield)) sb.AppendLine($"            Shield = ShieldData.{shield},");
            EmitVehicleWeapons(sb, r.Get("Ship.Weapons"), indent: "            ");
            EmitVehicleEquipment(sb, r.Get("Ship.Equipment"), indent: "            ");
            sb.AppendLine("        },");

            sb.AppendLine("    };");
            sb.AppendLine();
        }
        sb.AppendLine("}");
        Write("SpaceEncounterData.Generated.cs", sb.ToString());
        return _ctx.SpaceEncounters.Count;
    }

    // =================================================================
    // Species
    // =================================================================
    private int EmitSpecies()
    {
        if (_ctx.Species.Count == 0) return 0;
        var sb = new StringBuilder();
        sb.Append(Header);
        sb.AppendLine("using TerminalHyperspace.Models;");
        sb.AppendLine();
        sb.AppendLine("namespace TerminalHyperspace.Content;");
        sb.AppendLine();
        sb.AppendLine("public static partial class SpeciesData");
        sb.AppendLine("{");
        sb.AppendLine("    static partial void RegisterImported(List<Species> list)");
        sb.AppendLine("    {");
        foreach (var r in _ctx.Species)
        {
            sb.AppendLine("        list.Add(new Species");
            sb.AppendLine("        {");
            sb.AppendLine($"            Name = {Quote(r.Get("Name"))},");
            if (!string.IsNullOrEmpty(r.Get("Description")))
                sb.AppendLine($"            Description = {Quote(r.Get("Description"))},");
            sb.AppendLine("            BaseAttributes = new()");
            sb.AppendLine("            {");
            foreach (var a in Attrs)
            {
                var dice = r.Get(a); if (string.IsNullOrEmpty(dice)) dice = "0D";
                sb.AppendLine($"                [AttributeType.{a}] = {DiceLiteral(dice)},");
            }
            sb.AppendLine("            },");
            var bonuses = SplitKeyVal(r.Get("SkillBonuses"));
            if (bonuses.Count > 0)
            {
                sb.AppendLine("            SkillBonuses = new()");
                sb.AppendLine("            {");
                foreach (var (skill, dice) in bonuses)
                    sb.AppendLine($"                [SkillType.{skill}] = {DiceLiteral(dice)},");
                sb.AppendLine("            },");
            }
            sb.AppendLine("        });");
        }
        sb.AppendLine("    }");
        sb.AppendLine("}");
        Write("SpeciesData.Generated.cs", sb.ToString());
        return _ctx.Species.Count;
    }

