    // =================================================================
    // SkillChecks
    // =================================================================
    private int EmitSkillChecks()
    {
        if (_ctx.SkillChecks.Count == 0) return 0;
        var sb = new StringBuilder();
        sb.Append(Header);
        sb.AppendLine("using TerminalHyperspace.Models;");
        sb.AppendLine();
        sb.AppendLine("namespace TerminalHyperspace.Content;");
        sb.AppendLine();
        sb.AppendLine("public static partial class SkillCheckData");
        sb.AppendLine("{");

        // Public per-row members so they can be referenced by Id elsewhere if needed.
        foreach (var r in _ctx.SkillChecks)
        {
            var id = ToPascal(r.Get("Id"));
            sb.AppendLine($"    public static SkillCheckEvent Imported_{id} => new()");
            sb.AppendLine("    {");
            sb.AppendLine($"        Id = {Quote(r.Get("Id"))},");
            sb.AppendLine($"        Description = {Quote(r.Get("Description"))},");
            sb.AppendLine($"        SuccessText = {Quote(r.Get("SuccessText"))},");
            sb.AppendLine($"        FailText = {Quote(r.Get("FailText"))},");
            if (!string.IsNullOrEmpty(r.Get("FailPenaltyText")))
                sb.AppendLine($"        FailPenaltyText = {Quote(r.Get("FailPenaltyText"))},");
            sb.AppendLine($"        Skill = SkillType.{r.Get("Skill")},");
            var diff = string.IsNullOrEmpty(r.Get("Difficulty")) ? "Moderate" : r.Get("Difficulty");
            sb.AppendLine($"        Difficulty = CheckDifficulty.{diff},");
            sb.AppendLine($"        TargetNumber = {ParseInt(r.Get("TargetNumber"))},");
            sb.AppendLine($"        CreditReward = {ParseInt(r.Get("CreditReward"))},");
            sb.AppendLine($"        UpgradePointReward = {ParseInt(r.Get("UpgradePointReward"))},");
            if (ParseBool(r.Get("Repeatable")))
                sb.AppendLine("        Repeatable = true,");
            if (ParseInt(r.Get("CreditPenalty")) > 0)
                sb.AppendLine($"        CreditPenalty = {ParseInt(r.Get("CreditPenalty"))},");
            var combatNpc = r.Get("CombatNpcOnFail");
            if (!string.IsNullOrEmpty(combatNpc))
                sb.AppendLine($"        CombatNpcOnFail = NPCData.{combatNpc},");
            sb.AppendLine("    };");
            sb.AppendLine();
        }

        // Hook: register into LocationChecks / TalkChecks
        sb.AppendLine("    static partial void RegisterImportedLocationChecks(Dictionary<string, List<SkillCheckEvent>> map)");
        sb.AppendLine("    {");
        var byLocation = _ctx.SkillChecks
            .Where(r => !ParseBool(r.Get("TalkCheck")) && !string.IsNullOrEmpty(r.Get("LocationId")))
            .GroupBy(r => r.Get("LocationId"));
        foreach (var grp in byLocation)
        {
            sb.AppendLine($"        if (!map.TryGetValue({Quote(grp.Key)}, out var list_{Sanitize(grp.Key)}))");
            sb.AppendLine($"            map[{Quote(grp.Key)}] = list_{Sanitize(grp.Key)} = new();");
            foreach (var r in grp)
                sb.AppendLine($"        list_{Sanitize(grp.Key)}.Add(Imported_{ToPascal(r.Get("Id"))});");
        }
        sb.AppendLine("    }");
        sb.AppendLine();
        sb.AppendLine("    static partial void RegisterImportedTalkChecks(List<SkillCheckEvent> list)");
        sb.AppendLine("    {");
        foreach (var r in _ctx.SkillChecks.Where(r => ParseBool(r.Get("TalkCheck"))))
            sb.AppendLine($"        list.Add(Imported_{ToPascal(r.Get("Id"))});");
        sb.AppendLine("    }");

        sb.AppendLine("}");
        Write("SkillCheckData.Generated.cs", sb.ToString());
        return _ctx.SkillChecks.Count;
    }

    // =================================================================
    // Locations
    // =================================================================
    private int EmitLocations()
    {
        if (_ctx.Locations.Count == 0) return 0;
        var sb = new StringBuilder();
        sb.Append(Header);
        sb.AppendLine("using TerminalHyperspace.Models;");
        sb.AppendLine();
        sb.AppendLine("namespace TerminalHyperspace.Content;");
        sb.AppendLine();
        sb.AppendLine("public static partial class LocationData");
        sb.AppendLine("{");
        sb.AppendLine("    static partial void RegisterImported(Dictionary<string, Location> world)");
        sb.AppendLine("    {");
        foreach (var r in _ctx.Locations)
        {
            var id = r.Get("Id");
            sb.AppendLine($"        world[{Quote(id)}] = new Location");
            sb.AppendLine("        {");
            sb.AppendLine($"            Id = {Quote(id)},");
            sb.AppendLine($"            Name = {Quote(r.Get("Name"))},");
            if (!string.IsNullOrEmpty(r.Get("Description")))
                sb.AppendLine($"            Description = {Quote(r.Get("Description"))},");
            if (ParseBool(r.Get("IsSpace")))         sb.AppendLine("            IsSpace = true,");
            if (ParseBool(r.Get("IsSystemSpace")))   sb.AppendLine("            IsSystemSpace = true,");
            if (ParseBool(r.Get("RequiresVehicle"))) sb.AppendLine("            RequiresVehicle = true,");

            var clim = r.Get("Climate");
            if (!string.IsNullOrEmpty(clim) && !clim.Equals("Normal", StringComparison.OrdinalIgnoreCase))
                sb.AppendLine($"            Climate = Climate.{clim},");

            var coords = r.Get("HyperspaceCoordinates");
            if (!string.IsNullOrEmpty(coords))
            {
                var (x, y) = ParseCoords(coords);
                sb.AppendLine($"            HyperspaceCoordinates = new[] {{ {x}, {y} }},");
            }

            foreach (var f in new[] { "PlanetName", "StarSystemName", "SectorName", "TerritoryName" })
                if (!string.IsNullOrEmpty(r.Get(f)))
                    sb.AppendLine($"            {f} = {Quote(r.Get(f))},");

            var exits = SplitKeyVal(r.Get("Exits"));
            if (exits.Count > 0)
            {
                sb.AppendLine("            Exits = new()");
                sb.AppendLine("            {");
                foreach (var (dir, target) in exits)
                    sb.AppendLine($"                [{Quote(dir)}] = {Quote(target)},");
                sb.AppendLine("            },");
            }

            var encs = SplitSemi(r.Get("PossibleEncounters"));
            if (encs.Count > 0)
                sb.AppendLine($"            PossibleEncounters = new() {{ {string.Join(", ", encs.Select(n => $"NPCData.{n}"))} }},");

            if (!string.IsNullOrEmpty(r.Get("EncounterChance")))
                sb.AppendLine($"            EncounterChance = {ParseDouble(r.Get("EncounterChance")).ToString(System.Globalization.CultureInfo.InvariantCulture)},");

            var friendly = SplitSemi(r.Get("FriendlyNPCs"));
            if (friendly.Count > 0)
                sb.AppendLine($"            FriendlyNPCs = new() {{ {string.Join(", ", friendly.Select(n => $"NPCData.{n}"))} }},");

            if (ParseBool(r.Get("HasShop")))         sb.AppendLine("            HasShop = true,");
            if (ParseBool(r.Get("HasVehicleShop")))  sb.AppendLine("            HasVehicleShop = true,");

            var spaceEncs = SplitSemi(r.Get("SpaceEncounters"));
            if (spaceEncs.Count > 0)
                sb.AppendLine($"            SpaceEncounters = new() {{ {string.Join(", ", spaceEncs.Select(n => $"SpaceEncounterData.{n}"))} }},");

            if (!string.IsNullOrEmpty(r.Get("SpaceEncounterChance")))
                sb.AppendLine($"            SpaceEncounterChance = {ParseDouble(r.Get("SpaceEncounterChance")).ToString(System.Globalization.CultureInfo.InvariantCulture)},");

            var ambient = r.Get("AmbientMessages");
            if (!string.IsNullOrEmpty(ambient))
            {
                var lines = ambient.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
                if (lines.Length > 0)
                {
                    sb.AppendLine("            AmbientMessages = new()");
                    sb.AppendLine("            {");
                    foreach (var line in lines)
                        sb.AppendLine($"                {Quote(line)},");
                    sb.AppendLine("            },");
                }
            }

            sb.AppendLine("        };");
            sb.AppendLine();
        }
        sb.AppendLine("    }");
        sb.AppendLine("}");
        Write("LocationData.Generated.cs", sb.ToString());
        return _ctx.Locations.Count;
    }

    private static string Sanitize(string s)
        => new string(s.Select(c => char.IsLetterOrDigit(c) ? c : '_').ToArray());

    private static string ToPascal(string s)
    {
        var parts = s.Split(new[] { '_', '-', ' ' }, StringSplitOptions.RemoveEmptyEntries);
        return string.Concat(parts.Select(p => char.ToUpperInvariant(p[0]) + p[1..]));
    }
}
